INSERT INTO `ProductInfos` VALUES (1,'Sastav','INGREDIENTS: <br />AQUA / WATER, LACTOBACILLUS FERMENT LYSATE, CUCUMIS SATIVUS (CUCUMBER) FRUIT WATER, GLYCERIN, ALPHA-GLUCAN OLIGOSACCHARIDE, SACCHAROMYCES FERMENT, SILYBUM MARIANUM (MILK THISTLE) EXTRACT, LACTOBACILLUS FERMENT LYSATE FILTRATE, SODIUM PCA, MAGNESIUM PCA, ZINC PCA, SQUALANE, BETA GLUCAN, SALIX ALBA (WHITE WILLOW)  BARK EXTRACT, GLUCONOLACTONE, LEUCONOSTOC/RADISH ROOT FERMENT FILTRATE, MANGANESE PCA, OLEA EUROPAEA LEAF EXTRACT, SACCHAROMYCES/SEA SILT FERMENT, SACCHAROMYCES/ZINC FERMENT, SACCHAROMYCES/COPPER FERMENT, SACCHAROMYCES/MAGNESIUM FERMENT, SACCHAROMYCES/IRON FERMENT, SACCHAROMYCES/SILICON FERMENT, PISUM SATIVUM (PEA) PEPTIDE, SAMBUCUS NIGRA (ELDERBERRY) FRUIT EXTRACT, POLYMNIA SONCHIFOLIA (YACÓN) ROOT JUICE, XANTHAN GUM, SODIUM BENZOATE, JASMINUM OFFICINALE FLOWER OIL, CITRUS PARADISI PEEL OIL, MALTODEXTRIN, LACTOBACILLUS, LACTOBACILLUS FERMENT, LINALOOL, LIMONENE.',1,0,'2025-06-22 19:06:22.505795',0,'2025-06-22 19:06:22.505798'),(2,'Upotreba','Koristite svakodnevno prije redovne dnevne ili noćne njege. Fluidni koncentrat dolazi u nisko viskoznom obliku kako bi ga koža brzo upila, te iskoristila sve djelotvorne sastojke. Fluid nije namijenjen njezi kože već aktivnom djelovanju za zaštitu kako i smanjenje znakova starenja.',1,0,'2025-06-22 19:06:22.505802',0,'2025-06-22 19:06:22.505802'),(3,'Način čuvanja i napomene','Čuvati na sobnoj temperaturi',1,0,'2025-06-22 19:06:22.505802',0,'2025-06-22 19:06:22.505802'),(4,'Sastav','INGREDIENTS: <br />AQUA / WATER, CAMELLIA SINENSIS LEAF WATER, GLYCOLIC ACID, OCTADECENEDIOIC ACID, LEUCONOSTOC/RADISH ROOT FERMENT FILTRATE, CENTELLA ASIATICA EXTRACT, DEHYDROACETIC ACID, GLYCYRRHIZA GLABRA (LICORICE) ROOT EXTRACT, AVERRHOA CARAMBOLA FRUIT EXTRACT, PASSIFLORA INCARNATA FRUIT EXTRACT, ALOE BARBADENSIS LEAF EXTRACT, DIMETHYL SULFONE, ZINGIBER OFFICINALE ROOT EXTRACT, MENTHA PIPERITA LEAF EXTRACT, SALIX ALBA (WHITE WILLOW)  BARK EXTRACT, ACTINIDIA CHINENSIS (KIWI) FRUIT EXTRACT, GARCINIA MANGOSTANA FRUIT EXTRACT, ANANAS SATIVUS (PINEAPPLE) FRUIT EXTRACT, PUNICA GRANATUM EXTRACT, LITCHI CHINENSIS FRUIT EXTRACT, TOCOPHEROL, ZIZYPHUS JUJUBA FRUIT EXTRACT, PSIDIUM GUAJAVA FRUIT EXTRACT, CANNABIS SATIVA SEED OIL, BENZYL ALCOHOL, CAPRYLIC/CAPRIC TRIGLYCERIDE, POPULUS TREMULOIDES BARK EXTRACT, GLYCERIN, XANTHAN GUM, MARANTA ARUNDINACEA ROOT EXTRACT, SAMBUCUS NIGRA FRUIT EXTRACT, ROSA CANINA FRUIT EXTRACT, CANNABIDIOL - DERIVED FROM EXTRACT OR TINCTURE OR RESIN OF CANNABIS, CITRUS AURANTIFOLIA OIL, CITRUS AURANTIUM DULCIS PEEL OIL, SODIUM HYALURONATE, POLYURETHANE, CAMELLIA SINENSIS (GREEN TEA) LEAF EXTRACT, POLYVINYL ALCOHOL, PENTAERYTHRITOL, CELLULOSE GUM, DIDECYLDIMONIUM CHLORIDE, CITRAL, LINALOOL, LIMONENE, GERANIOL.',2,0,'2025-06-22 19:06:22.579336',0,'2025-06-22 19:06:22.579336'),(5,'Upotreba','Koristite svakodnevno prije redovne dnevne ili noćne njege. Može se ostaviti da djeluje te potom nanijeti 3-CBD moisturizer ili isprati vodom te potom nanijeti moisturizer.',2,0,'2025-06-22 19:06:22.579336',0,'2025-06-22 19:06:22.579336'),(6,'Način čuvanja i napomene','Čuvati na sobnoj temperaturi',2,0,'2025-06-22 19:06:22.579335',0,'2025-06-22 19:06:22.579335'),(7,'Sastav','INGREDIENTS: <br />PLUKENETIA VOLUBILIS (SACHA INCHI) SEED OIL, PRUNUS ARMENIACA KERNEL OIL, VITIS VINIFERA SEED OIL, LIMNANTHES ALBA SEED OIL, SILYBUM MARIANUM (MILK THISTLE) SEED OIL, LINOLEIC ACID, SQUALANE, CAPRYLIC/CAPRIC TRIGLYCERIDE, GLYCERIN, CORYLUS AVELLANA SEED OIL, CAMELINA SATIVA SEED OIL, COCOS NUCIFERA OIL, AQUA / WATER, CARTHAMUS TINCTORIUS (SAFFLOWER) SEED OIL, HELIANTHUS ANNUUS (SUNFLOWER) SEED OIL, RETINYL PALMITATE, ORYZA SATIVA (RICE) LIPIDS,  CITRULLUS LANATUS SEED OIL, JUGLANS REGIA SEED OIL, GLYCINE SOJA (SOYBEAN) SEED EXTRACT, PANTHENOL, SAMBUCUS NIGRA FRUIT EXTRACT, CHLAMYDOMONAS REINHARDTII EXTRACT, FRAGARIA VESCA (STRAWBERRY) FRUIT EXTRACT, CERAMIDE EOP, CERAMIDE NP, HIBISCUS ROSA-SINENSIS FLOWER EXTRACT, ELETTARIA CARDAMOMUM (CARDAMOM) FRUIT EXTRACT, POGOSTEMON CABLIN OIL, ROSA CANINA SEED EXTRACT, MALUS DOMESTICA FRUIT CELL CULTURE EXTRACT, ARGANIA SPINOSA CALLUS CULTURE EXTRACT, SILYBUM MARIANUM (MILK THISTLE) SEED OIL, PHOSPHOLIPIDS , DAUCUS CAROTA SATIVA SEED OIL, HIPPOPHAE RHAMNOIDES FRUIT OIL , LINOLENIC ACID, SPHINGOLIPIDS, GERANIOL.',3,0,'2025-06-22 19:06:22.601806',0,'2025-06-22 19:06:22.601806'),(8,'Upotreba','Koristite svakodnevno zasebno ili umiješati nekoliko kapi u dnevnu ili noćnu njegu.',3,0,'2025-06-22 19:06:22.601805',0,'2025-06-22 19:06:22.601805'),(9,'Način čuvanja i napomene','Čuvati na sobnoj temperaturi',3,0,'2025-06-22 19:06:22.601805',0,'2025-06-22 19:06:22.601805'),(10,'Sastav','AQUA / WATER, ASCORBIC ACID, SILYBUM MARIANUM SEED OIL, NIACINAMIDE, ROSA CANINA FRUIT/FLOWER EXTRACT, PANTHENOL, TOCOPHEROL, RETINYL PALMITATE, ROSA CANINA (ROSEHIP) SEED EXTRACT, SODIUM ASCORBYL PHOSPHATE, DIMETHYL SULFONE, LINOLEIC ACID, HYDROXYPROPYL METHYLCELLULOSE, XANTHAN GUM, PUNICA GRANATUM STEROLS, COCOS NUCIFERA (COCONUT) FRUIT EXTRACT, SODIUM HYALURONATE, LITSEA CUBEBA FRUIT OIL, LINOLENIC ACID, ASTAXANTHIN, LIMONENE*.<br />*iz prirodnih eteričnih ulja/from natural essential oils',4,0,'2025-06-22 19:06:22.636593',0,'2025-06-22 19:06:22.636593'),(11,'Upotreba','Koristite svakodnevno prije redovne dnevne ili noćne njege. Ovaj serum dolazi u nisko viskoznom obliku kako bi ga koža brzo upila te iskoristila sve djelotvorne sastojke. Nije namijenjen njezi kože, već aktivnom djelovanju za pomlađivanje i snažan detox kože. Savjet: Koristite vitamin C jednom dnevno i izbjegavajte korištenje vitamina C s AHA, BHA ili  retinolom.',4,0,'2025-06-22 19:06:22.636593',0,'2025-06-22 19:06:22.636593'),(12,'Način čuvanja i napomene','Čuvati na sobnoj temperaturi',4,0,'2025-06-22 19:06:22.636593',0,'2025-06-22 19:06:22.636593'),(13,'Sastav','INGREDIENTS: <br />AQUA / WATER, LACTOBACILLUS FERMENT LYSATE, GLYCERIN, SILYBUM MARIANUM (MILK THISTLE) SEED OIL, VITIS VINIFERA (GRAPE) SEED OIL, ALPHA-GLUCAN OLIG